    """Safe unpickler that only allows safe operations."""

    def find_class(self, module, name):
        # Only allow basic types that are safe to unpickle
        safe_modules = {
            'builtins': [
                'dict', 'list', 'tuple', 'set', 'frozenset',
                'int', 'float', 'str', 'bytes', 'bool', 'NoneType'
            ],
            '__builtin__': [  # For Python 2 compatibility
                'dict', 'list', 'tuple', 'set', 'frozenset',
                'int', 'float', 'str', 'bytes', 'bool', 'NoneType'
            ]
        }

        if module in safe_modules and name in safe_modules[module]:
            return getattr(__import__(module), name)
        else:
            raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


